INSERT INTO knowledge_documents (id, source_path, title, kind, tags, content, summary, chunk_count, is_archive, metadata, created_at, updated_at) VALUES
(gen_random_uuid(), 'kb/international/201', '电玩城国际化战略框架', 'spec', '{国际化,战略,扩张}', '电玩城国际化三步走战略框架：第一阶段（6-12月）选择东南亚作为桥头堡，印尼、越南、泰国为试点，利用华人商圈和购物中心合作切入；第二阶段（12-24月）拓展至中东和日韩，品牌授权+本地合股模式；第三阶段（24-36月）进入欧美市场，以IP主题店和全托管经营为主。每阶段需做营商环境评估（政治稳定性/外汇管制/劳工法规/知识产权四维评分）。风险对冲：与本地龙头合作持股≤49%，品牌管理费保底+分成模式，总部保留品牌IP所有权。泡泡玛特泰国店首年营收3亿泰铢为参考标杆。', '三步走国际化框架(东南亚→中东日韩→欧美)，含风险对冲策略', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/202', '跨境开店选址与进入模型', 'spec', '{国际化,选址,模型}', '五种海外开店进入模型对比：1）直营旗舰店——品牌强势市场，投资200-500万，控制力100%；2）合资公司——投资100-300万，持股49-51%；3）品牌授权——加盟费5-20万美元，年管理费3-8%；4）全托管管理——不投资但收管理费，适合高风险市场；5）电商虚拟店——低成本试水。选址原则：华人聚集区商场优先（租金贵15%但客流稳3倍），次选旅游商圈（季节性风险高但坪效峰值高），避免纯本地社区。签约注意：外汇汇出条款、争议仲裁地（香港/新加坡）、退出条款（提前6个月通知）。', '五种进入模型对比+选址三原则+签约要点', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/203', '海外市场法律合规清单', 'spec', '{国际化,合规,法律}', '海外开店必备法律合规清单八项：1）公司注册——LLC/PTE LTD最常见，注册资本5-50万美元；2）营业执照——娱乐场所经营许可（6-12月审批）；3）消防安全——NFPA标准，设备需CE/UL认证；4）劳工法规——最低工资/社保/工作时长/外籍员工配额；5）消费税/VAT——印尼11%/泰国7%/阿联酋5%；6）数据隐私——GDPR或类似法规，会员系统需本地服务器；7）知识产权——品牌专利提前注册防抢注；8）反洗钱——大额充值兑换需KYC。建议：聘请当地律所常法顾问，合同中英文双版本。', '八项海外法律合规清单+当地律所建议', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/204', '海外门店运营模式设计', 'spec', '{国际化,运营,模式}', '海外运营标准化与本地化二分法：标准化部分——品牌VI/核心设备选型/会员系统架构/定价策略框架/KPI体系。本地化部分——员工管理（东南亚重人情/中东重层级/欧美重流程）、营销渠道（东南亚TikTok+Line/中东Instagram+WhatsApp/欧美Facebook+Google）、支付方式（东南亚电子钱包/中东现金+卡/欧美卡+ApplePay）、促销节奏（宗教节日/购物节本地化）。人员配置：店长优先本地华人（双语+了解文化），总部派1-2名运营督导6月轮换，本地员工占比90%+。数据同步：当地时间23:00自动同步至总部。', '标准化与本地化二分法运营设计+人员配置方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/205', '全球游戏游艺市场趋势报告', 'spec', '{国际化,市场,行业洞察}', '2025-2026全球游戏游艺市场五大趋势：1）亚太区增长最快（CAGR14.2%），东南亚电竞馆+FEC双驱动；2）北美市场IP化加速，漫威星战主题体验馆坪效是普通店3倍；3）中东市场爆发（沙特2030愿景投640亿美元娱乐），迪拜FEC年增长25%；4）日本市场稳定年增3-5%，扭蛋+IP衍生品利润率45%+；5）拉美市场起步（巴西+墨西哥年增长18%），人民币结算是优势。进入难度排名：泰国→印尼→越南→阿联酋→沙特→日本→韩国→英国→美国。全球FEC市场规模：2025年528亿美元，2026预计592亿，2030预计960亿。', '五大区域市场趋势+进入难度排名+全球FEC市场规模预测', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/206', '海外供应链与设备出口指南', 'spec', '{国际化,供应链,设备}', '游戏设备出口全流程：1）出口认证——CE（欧盟）/UL（北美）/CCC原产地证/沙特SASO/印度BIS，认证周期2-6月，费用3000-15000美元/款；2）物流方案——海运30-45天到东南亚/60-90天到欧美，建议FCL整柜避免拼柜损坏；3）关税——东盟零关税（中国-东盟FTA），中东5%，欧美3-8%；4）安装维保——派工程师驻场2-4周安装，后续代理商或远程诊断；5）备件——区域备件仓（优选东南亚华侨仓库合作），30天安全库存。案例：某品牌出口泰国120台设备，物流8000美元，关税减免，安装2周，月营收45万泰铢。', '设备出口认证/物流/关税/安装/备件全流程指南', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/207', '跨境支付与资金管理', 'spec', '{国际化,财务,支付}', '跨境资金管理五大关键：1）多币种收款账户（HSBC汇丰/OCBC华侨银行多币种），资金归集T+1至T+3；2）汇率风险管理——日交易额超10万美元等值建议远期结汇，月均汇损控制在0.3%内；3）利润汇回——品牌费（5-8%允许汇出）+管理费+设备采购款三个通道；4）税务筹划——优先签有DTT国家，利用香港中间控股优化整体税负15-25%；5）财务对账——多币种自动对账取按币种P&L。推荐Airwallex/万里汇等平台，汇兑成本可降30-50%。', '五维跨境资金管理方案+平台推荐', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/208', '海外员工招聘与管理', 'spec', '{国际化,HR,管理}', '海外员工管理体系六项：1）招聘渠道——Jobstreet（印尼）/JobsDB（泰国）/NaukriGulf（中东）+猎头+华人社群，管理岗优先海外华人；2）薪酬——参考同行业75分位（东南亚店长1500-3000美元/月，中东3000-5000美元/月）；3）绩效考核——总部KPI框架+当地权重调整，季度OKR+年度360评估；4）培训——总部6周英文版课程，当地培训师认证制；5）签证——商务签（3月）/工作签（需当地社保纳税）/投资签（1-5年），提前6月启动；6）本地化政策——尊重当地节假日/祈祷室设置（中东必备）/本地用工比例70-90%。', '六项海外用工管理+薪酬对标+签证类型', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/209', '海外用户行为与文化适配', 'spec', '{国际化,用户,文化}', '四大区域用户差异与适配：东南亚——家庭客群60%+，周末套餐需求强，亲子设备35-40%，价格敏感，偏好现金+电子钱包。中东——客单价东南亚3倍，家庭包厢需求旺，女性专属时段有市场，斋月夜间营业至凌晨2点。日韩——年轻客群25-35岁，IP联动消费强（限定溢价300%+），偏好电子预付卡。欧美——18-35岁社交客群，酒吧联动模式接受，Subscription会员制，VR/AR高端设备。ARPU对比：东南亚5-8美元/中东15-25/日韩12-18/欧美18-30。每区域需调整设备配比、促销策略、服务流程。', '四大区域用户行为差异+ARPU对比+运营适配方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/210', '海外品牌营销本地化策略', 'spec', '{国际化,营销,品牌}', '海外品牌营销本地化五步法：1）品牌名与VI——中文保留+当地语音译意译，Logo颜色适配（泰国喜金/中东喜金白/日韩简约）；2）内容本地化——本地团队产出60%+总部模板20%+IP联动20%；3）渠道策略——东南亚TikTok+直播带货/中东Instagram+YouTube/日韩Twitter+LINE/欧美TikTok+Snapchat；4）KOL——东南亚百万粉娱乐类3000-30000美元/篇/中东生活类/日韩游戏二次元类；5）活动融入——宋干节/斋月/圣诞本地IP联动。首年营销占营收15-20%，成熟期降至8-12%。', '五大品牌本地化步骤+KOL策略+预算分配', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/211', '海外会员与CRM系统', 'spec', '{国际化,会员,系统}', '国际会员系统设计要点：1）架构——云原生多租户，总部统一后台+各市场独立前台，数据隔离合规；2）等级——统一银金钻框架+当地权益差异化；3）积分——暂不开放跨市场兑换，改区域性积分池；4）支付——对接当地GoPay/OVO/PromptPay/PayPay等；5）隐私——GDPR需DPA协议，最小化采集原则；6）多语言——支持10种语言（中/英/泰/印尼/越南/阿拉伯/日/韩/西/法），自动检测。CRM双轨制：总部核心数据分析+本地客群运营自主权。', '国际会员系统六大设计要点+多语言/隐私/支付方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/212', '海外安全与应急预案', 'spec', '{国际化,安全,应急}', '海外门店安全运营六项：1）消防——NFPA/EN标准配置，设备加贴当地安全标签，季度演练；2）安防——24h监控（本地+云端+总部实时），夜间防盗，现金不过夜；3）人身——安检（中东必要），安保配置（高峰），监控死角不设设备；4）数据——会员数据本地存储，设备数据脱敏传总部，防火墙；5）预案——火灾/伤亡/群体/舆情四类中英双语版，季度演练；6）保险——财产险+公责险（建议保额500万美元+）+工伤+营业中断，年保费约营收0.5-1.2%。推荐与AIA/AXA合作定制。', '六项海外安全运营+保险方案建议', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/213', '海外合资与授权经营', 'spec', '{国际化,合作,法律}', '海外合资与授权对比：合资模式持股49-51%，需明确董事席位/否决权/退出/分红/IP归属五大条款。授权模式前期加盟费+年管理费3-8%，需完善手册和监督机制。六大关键条款：1）品牌使用权（地域/品质/更新）；2）设备采购权；3）系统强制使用SOP；4）总部巡检+神秘访客权；5）竞业禁止（合同期+终止后2年）；6）财务透明（月报+年审计+利润分配公式）。典型案例：泡泡玛特泰国（持股65%）、Genting Casinos加盟、SEGA乐园授权。', '合资vs授权模式+六大关键合同条款+行业案例', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/214', '海外设备选型与采购', 'spec', '{国际化,设备,采购}', '海外设备选型六项原则：1）可靠性优先——故障率<2%/年，备件通用性优先；2）宽电压100-240V自动适应50/60Hz；3）多语言系统（中/英/当地语），UI远程更新；4）认证合规清单（CE/UL/SASO等），每款认证3000-15000美元；5）运输——标准集装箱优化，防潮防震海运40天，备件单独装箱；6）售后——区域维修中心（泰国/迪拜/荷兰），24h远程+48h上门（主要城市），备件72h到达。采购节奏：首批4-6款各5-10台，3月观察期后再批量。', '六项设备选型+认证/运输/售后方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/215', '海外竞品分析与卡位策略', 'spec', '{国际化,竞品,策略}', '四大市场竞争格局：1）东南亚——本土+日系品牌（TimeZone/WonderStar），定价低，设备老旧；卡位：中高端（5-10元/次）+亲子套餐差异化。2）中东——竞品少且高端（VR Park/IMG Worlds），票价20-60美元；卡位：中端（8-15美元）+家庭FEC覆盖中产。3）日韩——Round1/Sega强势，需IP差异化（国潮IP）。4）欧美——Dave&Buster/Main Event；卡位：亚洲文化特色（美食+装饰+IP）聚焦华人+文化爱好者。每市场Top3竞品建立档案（营收/客单价/设备/评价/社媒），季度更新。', '四大市场竞争分析+差异化卡位策略', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/216', '海外投资回报测算', 'spec', '{国际化,财务,投资}', '海外门店投资测算标准模型：假设条件（东南亚500-800㎡），设备投入15-25万美元（40-60台），装修20-35万美元，开业营销3-5万美元，运营资金5万美元，总投资43-70万美元/店。月营收6-15万美元，旺季×1.5。成本结构：房租12-20%/人工15-22%/设备折旧8-10%/电费3-5%/营销5-8%/管理3-5%。毛利率60-70%，净利率15-25%，回收期18-30月。敏感性排序：客流>客单价>房租>人工>电费。各市场差异：东南亚净利18-22%/回收24-30月/中东22-28%/18-24月/日韩15-20%/24-36月/欧美20-25%/18-30月。评估：IRR≥20%，NPV>0（折现12%），平衡客流日均150-250人。', '海外门店投资测算模型+四大市场对比', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/217', '海外开业筹备SOP', 'spec', '{国际化,开业,流程}', '海外门店90天筹备SOP（D-90至D-0）：D-90至D-60——公司注册6-8周/选址签约/团队组建；D-60至D-45——装修设计深化/设备采购下单/消防报建/招聘启动；D-45至D-30——装修施工45天/设备发运/培训教材/系统部署；D-30至D-15——装修收尾/设备清关7天/培训开营；D-15至D-7——设备安装调试/试运营准备/KOL预热；D-7至D-0——试运营7天（内部+家属）/全员演练；D-Day——正式开业，首日营收≥预估50%即可。关键里程碑：消防通过（D-30前）/设备验收（D-7前）/试运营客诉≤5起/天。', '90天海外开业筹备SOP+三大关键里程碑', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/218', '海外跨文化培训方案', 'spec', '{国际化,培训,文化}', '海外四级跨文化培训体系：L1基础（入职2周内）——品牌文化2课时/服务标准4课时/设备操作8课时/安全规范4课时/系统使用4课时；L2进阶（1-3月）——销售4课时/客诉4课时/本地文化4课时/协作4课时；L3提升（3-6月）——设备维护8课时/运营管理8课时/法规4课时/财务基础4课时；L4管理（6月+/晋升）——团队管理12课时/数据分析8课时/营销8课时/领导力8课时。形式：总部录播多语字幕+本地讲师面授+实操考核。考核标准：L1通过≥90%可上岗，L2-4晋升必过，不合格重考1次仍不过调岗。激励：每级完成奖励100-500美元。', '四级海外培训体系+考核标准+激励方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/219', '海外数据管理与报表', 'spec', '{国际化,数据,报表}', '海外报表四层级：日报（当日营收/客流/开工率/ARPU/异常告警20%+突降），周报（营收趋势/客群画像/活动效果/人效），月报（P&L+本币+集团合并美元+预算对比+环比同比+区域排名），季报（投资回报/市占率/战略调整）。系统要求：统一数据字典（中英文）、自动时区转换（本地时间+UTC+8总部）、多币种换算（固定+实时汇率双记录）。数据安全：本地存储+云备份，总部只读脱敏查询，日结自动同步，断网72h数据本地缓存。', '四级报表体系+系统架构+数据安全方案', 3, false, '{}'::jsonb, NOW(), NOW()),
(gen_random_uuid(), 'kb/international/220', '海外舆情与PR管理', 'spec', '{国际化,舆情,PR}', '海外舆情管理五维体系：1）监控——Brandwatch/Talkwalker多语言监控，24/7频率，告警阈值日负面≥5条；2）分级处理——L1单客投诉一线24h/L2群体投诉+媒体48h回复72h解决/L3安全事件CEO介入24h危机会议；3）危机SOP——确认事实1h→内部通报2h→统一口径4h→对外声明6-12h→跟进；4）日常PR——季度媒体交流会+KOL维护+社区活动每季度1次；5）差评处理——道歉+补偿+24h回复+不删评（合规），中英双语模板。预算：年PR预算20%为危机预备金。', '五维舆情管理+危机SOP+PR日常维护方案', 3, false, '{}'::jsonb, NOW(), NOW());
